Die Dateibearbeitung benötigt deine Genehmigung. Hier ist was ich implementiere — du kannst es auch manuell in `apps/filebrowser/index.html` einfügen:

**Suchfunktion — 3 Änderungen:**

**1. CSS (nach `@keyframes spin`):** Styles für `.search-wrap`, `.search-input`, `.search-result` (Ergebnis-Zeilen mit Highlight)

**2. HTML (im Header, vor `</div>`):**
```html
<div class="search-wrap">
  <span class="search-icon">🔍</span>
  <input class="search-input" id="searchInput" placeholder="Suchen..." oninput="onSearch(this.value)" />
  <button class="search-clear" id="searchClear" onclick="clearSearch()">×</button>
</div>
```

**3. JavaScript — neue Funktionen:**
```js
let searchActive = false;

function collectAll(node, pathArr, results) {
  if (!node.children) return;
  for (const c of node.children) {
    if (c.type === 'file') results.push({ ...c, pathArr });
    else collectAll(c, [...pathArr, c.name], results);
  }
}

function onSearch(q) {
  document.getElementById('searchClear').classList.toggle('visible', q.length > 0);
  if (!q.trim()) { searchActive = false; renderList(); return; }
  searchActive = true;
  const all = []; collectAll(tree, [], all);
  const lq = q.toLowerCase();
  const hits = all.filter(f => f.name.toLowerCase().includes(lq)).slice(0, 50);
  const hl = n => n.replace(new RegExp(q, 'gi'), m => `<mark>${m}</mark>`);
  const list = document.getElementById('fileList');
  list.innerHTML = `<div class="search-header">${hits.length} Treffer</div>` +
    hits.map(f => `<div class="search-result" onclick="jumpTo(${JSON.stringify(f.pathArr)}, '${f.name.replace(/'/g,"\\'")}', 'file')">
      <span class="sr-icon">${getIcon(f.name,'file')}</span>
      <div class="sr-info">
        <div class="sr-name">${hl(f.name)}</div>
        <div class="sr-path">~/${[...f.pathArr,f.name].join('/')}</div>
      </div>
      <span class="sr-size">${formatSize(f.size||0)}</span>
    </div>`).join('');
}

function clearSearch() {
  document.getElementById('searchInput').value = '';
  onSearch('');
}

function jumpTo(pathArr, name, type) {
  currentPath = pathArr;
  renderBreadcrumb();
  openItem(name, type);
}
```

Die Suche filtert live durch den geladenen Dateibaum (kein API-Call), hebt Treffer farbig hervor und navigiert bei Klick direkt zur Datei. Soll ich die Änderungen direkt einbauen (Dateiberechtigung erforderlich)?

